import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import axios from 'axios';

function ImageAnalyzer() {
  const [selectedImage, setSelectedImage] = useState(null);
  const [preview, setPreview] = useState(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');
  const [results, setResults] = useState(null);
  const navigate = useNavigate();

  const handleImageSelect = (e) => {
    const file = e.target.files?.[0];
    if (file) {
      setSelectedImage(file);
      const reader = new FileReader();
      reader.onload = (event) => {
        setPreview(event.target?.result);
      };
      reader.readAsDataURL(file);
      setError('');
      setResults(null);
    }
  };

  const handleAnalyze = async () => {
    if (!selectedImage) {
      setError('Please select an image first');
      return;
    }

    setLoading(true);
    setError('');
    setResults(null);

    try {
      compressImage(selectedImage, async (compressedBase64) => {
        const response = await axios.post('/api/ai/analyze-image', {
          image: compressedBase64,
          imageType: 'image/jpeg'
        });

        const productsResponse = await axios.get('/api/products');
        const allProducts = productsResponse.data;

        const keywords = response.data.keywords || [];
        const matchingProducts = allProducts.filter(product => {
          const productName = product.name.toLowerCase();
          const productCategory = (product.category || '').toLowerCase();

          return keywords.some(keyword => {
            const kw = keyword.toLowerCase();
            return productName.includes(kw) || productCategory.includes(kw);
          });
        });

        setResults({
          analysis: response.data.analysis,
          keywords: keywords,
          fabric: response.data.fabric,
          item: response.data.item,
          products: matchingProducts.slice(0, 9)
        });

        setLoading(false);
      });
    } catch (err) {
      setError(err.response?.data?.message || 'Failed to analyze image');
      console.error('Error:', err);
      setLoading(false);
    }
  };

  const compressImage = (file, callback) => {
    const reader = new FileReader();
    reader.readAsDataURL(file);
    reader.onload = (event) => {
      const img = new Image();
      img.src = event.target.result;
      img.onload = () => {
        const canvas = document.createElement('canvas');
        let width = img.width;
        let height = img.height;

        const maxDim = 2048;
        if (width > height) {
          if (width > maxDim) {
            height = Math.round((height * maxDim) / width);
            width = maxDim;
          }
        } else {
          if (height > maxDim) {
            width = Math.round((width * maxDim) / height);
            height = maxDim;
          }
        }

        canvas.width = width;
        canvas.height = height;

        const ctx = canvas.getContext('2d');
        ctx.drawImage(img, 0, 0, width, height);

        const compressedBase64 = canvas.toDataURL('image/jpeg', 0.85).split(',')[1];
        callback(compressedBase64);
      };
    };
  };

  const handleClear = () => {
    setSelectedImage(null);
    setPreview(null);
    setResults(null);
    setError('');
  };

  return (
    <div style={{ minHeight: '100vh', backgroundColor: '#fff' }}>
      {/* Top Title */}
      <div style={{
        padding: '60px 50px 40px',
        borderBottom: '1px solid #f0f0f0'
      }}>
        <h1 style={{
          fontSize: '48px',
          fontWeight: '300',
          letterSpacing: '1px',
          color: '#000',
          margin: '0'
        }}>
          STYLE DISCOVERY
        </h1>
      </div>

      {/* Main Showcase Layout */}
      <div style={{
        display: 'grid',
        gridTemplateColumns: '1fr 2fr 1fr',
        gap: '60px',
        padding: '80px 50px',
        alignItems: 'start',
        minHeight: '600px'
      }}>
        {/* Left - Upload Area */}
        <div>
          <div
            onDragOver={(e) => e.preventDefault()}
            onDrop={(e) => {
              e.preventDefault();
              const file = e.dataTransfer.files[0];
              if (file) {
                const event = { target: { files: [file] } };
                handleImageSelect(event);
              }
            }}
            style={{
              border: '1px solid #ddd',
              padding: '40px 30px',
              textAlign: 'center',
              cursor: 'pointer',
              marginBottom: '30px',
              backgroundColor: '#fafafa',
              transition: 'all 0.3s'
            }}
            onMouseEnter={(e) => {
              e.currentTarget.style.backgroundColor = '#f5f5f5';
            }}
            onMouseLeave={(e) => {
              e.currentTarget.style.backgroundColor = '#fafafa';
            }}
          >
            <input
              type="file"
              accept="image/*"
              onChange={handleImageSelect}
              style={{ display: 'none' }}
              id="image-input"
            />

            <label htmlFor="image-input" style={{ cursor: 'pointer', display: 'block' }}>
              <div style={{ fontSize: '32px', marginBottom: '15px' }}>📸</div>
              <p style={{
                fontSize: '13px',
                color: '#000',
                margin: '0 0 5px 0',
                fontWeight: '500'
              }}>
                Click to upload
              </p>
              <p style={{
                fontSize: '11px',
                color: '#999',
                margin: '0'
              }}>
                or drag and drop
              </p>
            </label>
          </div>

          {selectedImage && (
            <div style={{ display: 'flex', gap: '10px', flexDirection: 'column' }}>
              <button
                onClick={handleAnalyze}
                disabled={loading}
                style={{
                  padding: '12px 16px',
                  backgroundColor: loading ? '#ccc' : '#000',
                  color: '#fff',
                  border: 'none',
                  fontSize: '11px',
                  fontWeight: '600',
                  letterSpacing: '0.8px',
                  textTransform: 'uppercase',
                  cursor: loading ? 'not-allowed' : 'pointer',
                  transition: 'all 0.2s'
                }}
              >
                {loading ? 'Analyzing...' : 'Analyze'}
              </button>

              <button
                onClick={handleClear}
                style={{
                  padding: '12px 16px',
                  backgroundColor: '#fff',
                  color: '#000',
                  border: '1px solid #000',
                  fontSize: '11px',
                  fontWeight: '600',
                  letterSpacing: '0.8px',
                  textTransform: 'uppercase',
                  cursor: 'pointer'
                }}
              >
                Clear
              </button>
            </div>
          )}
        </div>

        {/* Center - Featured Image */}
        <div style={{
          display: 'flex',
          alignItems: 'center',
          justifyContent: 'center',
          minHeight: '400px',
          backgroundColor: '#f5f5f5',
          border: '1px solid #f0f0f0'
        }}>
          {preview ? (
            <img
              src={preview}
              alt="Preview"
              style={{
                maxWidth: '100%',
                maxHeight: '400px',
                objectFit: 'contain'
              }}
            />
          ) : (
            <p style={{ color: '#999', fontSize: '13px' }}>Upload image to preview</p>
          )}
        </div>

        {/* Right - Analysis Results (Vertical) */}
        <div style={{
          display: 'flex',
          flexDirection: 'column',
          justifyContent: 'flex-start',
          writingMode: 'vertical-rl',
          textOrientation: 'mixed'
        }}>
          {results ? (
            <div style={{
              color: '#000',
              fontSize: '24px',
              fontWeight: '600',
              letterSpacing: '1px',
              textTransform: 'uppercase'
            }}>
              {results.item || 'Fashion Item'}
            </div>
          ) : (
            <div style={{
              color: '#999',
              fontSize: '18px',
              fontWeight: '500'
            }}>
              Analysis
            </div>
          )}
        </div>
      </div>

      {/* Analysis Details Below */}
      {results && (
        <div style={{
          padding: '40px 50px',
          borderTop: '1px solid #f0f0f0',
          borderBottom: '1px solid #f0f0f0',
          marginBottom: '60px'
        }}>
          <div style={{ maxWidth: '800px' }}>
            <h3 style={{
              fontSize: '12px',
              fontWeight: '600',
              letterSpacing: '0.8px',
              color: '#000',
              margin: '0 0 15px 0',
              textTransform: 'uppercase'
            }}>
              Analysis
            </h3>
            <p style={{
              fontSize: '13px',
              color: '#333',
              lineHeight: '1.7',
              margin: '0 0 20px 0'
            }}>
              {results.analysis}
            </p>

            {(results.item || results.fabric) && (
              <div style={{ display: 'flex', gap: '10px', flexWrap: 'wrap' }}>
                {results.item && (
                  <span style={{
                    backgroundColor: '#000',
                    color: '#fff',
                    padding: '6px 12px',
                    fontSize: '10px',
                    fontWeight: '600',
                    letterSpacing: '0.5px',
                    textTransform: 'uppercase'
                  }}>
                    {results.item}
                  </span>
                )}
                {results.fabric && (
                  <span style={{
                    backgroundColor: '#333',
                    color: '#fff',
                    padding: '6px 12px',
                    fontSize: '10px',
                    fontWeight: '600',
                    letterSpacing: '0.5px',
                    textTransform: 'uppercase'
                  }}>
                    {results.fabric}
                  </span>
                )}
              </div>
            )}

            {results.keywords && results.keywords.length > 0 && (
              <div style={{ marginTop: '20px' }}>
                <p style={{
                  fontSize: '10px',
                  fontWeight: '600',
                  color: '#666',
                  textTransform: 'uppercase',
                  margin: '0 0 10px 0'
                }}>
                  Keywords
                </p>
                <div style={{ display: 'flex', flexWrap: 'wrap', gap: '8px' }}>
                  {results.keywords.map((keyword, idx) => (
                    <span
                      key={idx}
                      style={{
                        backgroundColor: '#e8e8e8',
                        color: '#333',
                        padding: '5px 10px',
                        fontSize: '10px',
                        textTransform: 'capitalize'
                      }}
                    >
                      {keyword}
                    </span>
                  ))}
                </div>
              </div>
            )}
          </div>
        </div>
      )}

      {/* Products Grid */}
      {results && results.products.length > 0 && (
        <div style={{ padding: '60px 50px' }}>
          <h2 style={{
            fontSize: '12px',
            fontWeight: '600',
            letterSpacing: '0.8px',
            color: '#000',
            margin: '0 0 40px 0',
            textTransform: 'uppercase'
          }}>
            Similar Products ({results.products.length})
          </h2>

          <div style={{
            display: 'grid',
            gridTemplateColumns: 'repeat(3, 1fr)',
            gap: '0'
          }}>
            {results.products.map(product => (
              <div
                key={product._id}
                onClick={() => navigate(`/product/${product._id}`)}
                style={{
                  borderRight: '1px solid #f0f0f0',
                  borderBottom: '1px solid #f0f0f0',
                  cursor: 'pointer'
                }}
              >
                <div style={{
                  aspectRatio: '1',
                  backgroundColor: '#f5f5f5',
                  display: 'flex',
                  alignItems: 'center',
                  justifyContent: 'center',
                  overflow: 'hidden'
                }}>
                  <img
                    src={product.media?.featured || `/products/${product._id}.jpg`}
                    alt={product.name}
                    style={{
                      width: '100%',
                      height: '100%',
                      objectFit: 'cover'
                    }}
                  />
                </div>

                <div style={{ padding: '20px' }}>
                  <h4 style={{
                    fontSize: '11px',
                    fontWeight: '600',
                    letterSpacing: '0.5px',
                    color: '#000',
                    margin: '0 0 8px 0',
                    textTransform: 'uppercase'
                  }}>
                    {product.name}
                  </h4>
                  <p style={{
                    fontSize: '12px',
                    fontWeight: '500',
                    color: '#000',
                    margin: '0'
                  }}>
                    ${product.price}
                  </p>
                </div>
              </div>
            ))}
          </div>
        </div>
      )}

      {error && (
        <div style={{
          padding: '20px 50px',
          backgroundColor: '#ffebee',
          color: '#d32f2f',
          fontSize: '12px'
        }}>
          {error}
        </div>
      )}
    </div>
  );
}

export default ImageAnalyzer;
